CREATE OR REPLACE FUNCTION public.upper(text)
  RETURNS text
  LANGUAGE sql
  IMMUTABLE PARALLEL SAFE STRICT
AS $function$
  SELECT upper($1);
$function$;
CREATE OR REPLACE FUNCTION public.immutable_unaccent(x text)
    RETURNS text
    LANGUAGE sql
    IMMUTABLE
    PARALLEL SAFE
    AS $function$
    SELECT
        unaccent($1);
$function$;
CREATE OR REPLACE FUNCTION public.immutable_unaccent_upper(text)
    RETURNS text
    LANGUAGE plpgsql
    IMMUTABLE
    PARALLEL SAFE
    AS $function$
BEGIN
    RETURN upper(public.unaccent($1));
END;
$function$;
CREATE OR REPLACE FUNCTION public.immutable_remove_spaces_unaccent_upper(text)
    RETURNS text
    LANGUAGE plpgsql
    IMMUTABLE
    PARALLEL SAFE
    AS $function$
BEGIN
    RETURN replace(public.upper(public.unaccent($1)), ' ', '');
END;
$function$;
CREATE OR REPLACE FUNCTION immutable_optimize_phone_number(text)
    RETURNS text
    LANGUAGE plpgsql
    IMMUTABLE
    AS $function$
BEGIN
RETURN regexp_replace($1, '[^0-9]', '', 'g');
END;
$function$;
CREATE OR REPLACE FUNCTION public.extract_and_normalize_phones(jsonb)
RETURNS text[] AS $$
DECLARE
phones text[];
    phone_json jsonb;
BEGIN
    phones := '{}';

FOR phone_json IN
SELECT * FROM jsonb_path_query($1, '$.telecom[*] ? (@.system == "phone").value')
                  LOOP
    phones := array_append(phones, immutable_optimize_phone_number(phone_json #>> '{}'));
END LOOP;

RETURN phones;
END;
$$ LANGUAGE plpgsql IMMUTABLE;
